import{_ as a,o as e,c as r,a0 as o}from"./chunks/framework.CED9SG98.js";const p=JSON.parse('{"title":"90%的 Karpathy 同款知识库，注定要吃灰","description":"Andrew 关于 AI 知识库陷阱的深度反思，提出 DIKW 模型与思考三问法，区分 AI 应做之事与人的不可替代性","frontmatter":{"type":"Source","title":"90%的 Karpathy 同款知识库，注定要吃灰","description":"Andrew 关于 AI 知识库陷阱的深度反思，提出 DIKW 模型与思考三问法，区分 AI 应做之事与人的不可替代性","source_url":"https://www.xiaohongshu.com/explore/ (小红书)","source_title":"90%的 Karpathy 同款知识库，注定要吃灰","source_author":"Andrew","source_platform":"小红书","ingest_date":"2026-07-12T00:00:00.000Z","access_date":"2026-07-12T00:00:00.000Z","tags":["知识管理","PKMS","AI认知","DIKW","Karpathy"],"status":"compiled","review_count":0,"last_review":"2026-07-12T00:00:00.000Z","next_review":"2026-07-13T00:00:00.000Z"},"headers":[],"relativePath":"wiki/sources/2026-07-12-karpathy-zhishiku-huiche.md","filePath":"wiki/sources/2026-07-12-karpathy-zhishiku-huiche.md"}'),i={name:"wiki/sources/2026-07-12-karpathy-zhishiku-huiche.md"};function l(s,t,n,h,d,c){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="_90-的-karpathy-同款知识库-注定要吃灰" tabindex="-1">90%的 Karpathy 同款知识库，注定要吃灰 <a class="header-anchor" href="#_90-的-karpathy-同款知识库-注定要吃灰" aria-label="Permalink to &quot;90%的 Karpathy 同款知识库，注定要吃灰&quot;">​</a></h1><blockquote><p>原文为小红书 Andrew 的长文，OCR 转录自 14 页截图。</p></blockquote><h2 id="核心论点" tabindex="-1">核心论点 <a class="header-anchor" href="#核心论点" aria-label="Permalink to &quot;核心论点&quot;">​</a></h2><p>AI 知识库的真正价值不取决于工具的精美程度，而取决于<strong>使用者的判断力</strong>。Karpathy 的知识库之所以有效，是因为他是那个领域顶尖的思考者，而非他的文件夹结构。</p><h2 id="关键概念" tabindex="-1">关键概念 <a class="header-anchor" href="#关键概念" aria-label="Permalink to &quot;关键概念&quot;">​</a></h2><h3 id="dikw-模型-知识内化金字塔" tabindex="-1">DIKW 模型（知识内化金字塔） <a class="header-anchor" href="#dikw-模型-知识内化金字塔" aria-label="Permalink to &quot;DIKW 模型（知识内化金字塔）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>手中数据 → 眼中信息 → 脑中知识 → 口中智慧</span></span></code></pre></div><ul><li><strong>数据 → 信息</strong>：需要主动解读</li><li><strong>信息 → 知识</strong>：需要主动思考</li><li><strong>知识 → 智慧</strong>：需要主动实践</li></ul><p><strong>核心洞察</strong>：AI 可以帮你把一楼（数据层）装修得极度漂亮，但二到四楼的跃迁必须靠人自己完成。</p><h3 id="ai-知识库的三大危险" tabindex="-1">AI 知识库的三大危险 <a class="header-anchor" href="#ai-知识库的三大危险" aria-label="Permalink to &quot;AI 知识库的三大危险&quot;">​</a></h3><ol><li><strong>错觉陷阱</strong>：一键总结让你误以为已完成理解，实际只是收集</li><li><strong>认知退化</strong>：满足了囤积欲和假性学习欲，却让大脑持续退化</li><li><strong>主权外包</strong>：把判断、选择、思考外包给 AI，数据永远无法跃迁为知识</li></ol><h3 id="ai-的正确位置" tabindex="-1">AI 的正确位置 <a class="header-anchor" href="#ai-的正确位置" aria-label="Permalink to &quot;AI 的正确位置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>交给 AI（体力活）</th><th>必须自己来（主权）</th></tr></thead><tbody><tr><td>整理、归档、提炼</td><td>判断什么值得知道</td></tr><tr><td>对比、关联、查漏</td><td>为什么关心这个方向</td></tr><tr><td>维护、更新</td><td>这跟我的目标有什么关系</td></tr><tr><td></td><td>我接下来该怎么做</td></tr></tbody></table><h3 id="思考三问法-最小行动方案" tabindex="-1">思考三问法（最小行动方案） <a class="header-anchor" href="#思考三问法-最小行动方案" aria-label="Permalink to &quot;思考三问法（最小行动方案）&quot;">​</a></h3><p>花 2 分钟回答这三个问题：</p><ol><li><strong>哪句话最击中你？</strong> → 用感受完成取舍和判断</li><li><strong>为什么触动到了我？</strong> → 动用大脑深度加工，联系过往经历</li><li><strong>接下来 2 分钟我能做什么？</strong> → 给自己一个临近的 deadline，行动概率飞跃</li></ol><blockquote><p>&quot;你唯一需要做的，就是忠于你内心的感受，肆无忌惮地把你心中所有的想法、情绪、甚至是脏话全部尽情地说出来。&quot;</p></blockquote><h3 id="纳瓦尔的一句话" tabindex="-1">纳瓦尔的一句话 <a class="header-anchor" href="#纳瓦尔的一句话" aria-label="Permalink to &quot;纳瓦尔的一句话&quot;">​</a></h3><blockquote><p><em>AI can generate anything you want, but that means the world is going to be full of average.</em></p></blockquote><p>最稀缺的不是模型、提示词或赛道——<strong>最稀缺的是你自己</strong>。</p><h2 id="关联" tabindex="-1">关联 <a class="header-anchor" href="#关联" aria-label="Permalink to &quot;关联&quot;">​</a></h2><ul><li>[[concepts/DIKW]] — 数据-信息-知识-智慧模型</li><li>[[concepts/PKMS]] — 个人知识管理系统（本系统的设计理念与此文高度一致）</li><li>[[entities/Karpathy]] — Andrej Karpathy，知识库实践的标杆人物</li><li>[[concepts/AI-Assisted-Thinking]] — AI 辅助思考的边界</li></ul><h2 id="引用原文" tabindex="-1">引用原文 <a class="header-anchor" href="#引用原文" aria-label="Permalink to &quot;引用原文&quot;">​</a></h2><blockquote><p>&quot;AI 可以替你整理知识，但不能替你决定什么值得知道。&quot; &quot;工具放大了他的能力。但能力是他自己的。&quot; &quot;你是不可替代的，这个世界上任何一个顶级、昂贵的模型都没办法替代。&quot;</p></blockquote><hr><p><em>原文: 小红书 Andrew说, 2026.06.18</em></p>',26)])])}const b=a(i,[["render",l]]);export{p as __pageData,b as default};
